INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(11, 1, '12', '주주 권리', '문서에서 주주의 3가지 핵심 권리 중 "경제적 권리"에 해당하는 것은?', '의결권과 주주제안권', '공시의무와 회계장부 열람권', '배당과 자사주 소각', '이사회 참가권과 감사청구권', 3, '문서 A.1-1 주주의 3가지 핵심권리 표에서 경제적 권리는 이익을 나눠받을 권리로 배당(Dividend)과 자사주 소각(Share Buyback & Cancellation)을 포함한다고 설명합니다.'),
(11, 2, '12', '주주 권리', '문서에서 자사주 소각(Share Buyback & Cancellation)이 주주에게 유리한 이유로 제시된 것은?', '주주에게 즉시 현금이 지급되어 배당과 동일한 효과가 있다', '발행 주식 수가 줄어들어 남은 주주의 주식 1주 가치가 높아진다', '회사의 부채가 감소하여 재무 건전성이 높아진다', '의결권 없는 우선주가 보통주로 전환되어 의결권이 생긴다', 2, '문서 A.1-1에서 자사주 소각은 회사가 주식을 사서 없애버려 발행 주식 수가 줄어들고, 같은 100주여도 전체에서 내 비율이 더 커져 주주 가치가 상승한다고 설명합니다.'),
(11, 3, '12', '주주 권리', '문서에서 주주제안권(株主提案權) 행사 조건으로 제시된 것은?', '발행주식의 3% 이상을 1개월 이상 보유한 주주', '발행주식의 1% 이상을 6개월 이상 보유하고 주주총회 6주 전까지 서면 제출', '발행주식의 0.1% 이상을 12개월 이상 보유한 주주', '단 1주만 보유해도 의결권 위임장을 통해 언제든 제출 가능', 2, '문서 A.1-1 경영적 권리 섹션에서 주주제안권 행사 조건은 발행주식의 1% 이상(코스피 대형사 0.5%)을 6개월 이상 보유한 주주가 주주총회 6주 전까지 서면으로 제출해야 한다고 설명합니다.'),
(11, 4, '12', '주식 시장', '문서에서 코스닥(KOSDAQ)의 특성으로 제시된 것은?', '자기자본 300억 이상 높은 요건으로 대형 우량기업 중심', '낮은 요건의 기술·바이오·중소기업 중심 성장성 시장', '가장 낮은 요건의 초기 벤처기업 대상 시장', '비상장 장외 거래 시장으로 거래소 없이 운영', 2, '문서 A.2 주식 시장 표에서 코스닥(KOSDAQ)은 낮은 요건의 성장성 중심 시장으로 기술·바이오·중소기업이 대표 기업이라고 설명합니다.'),
(11, 5, '12', 'IPO 상장', '문서에서 IPO(기업공개) 상장 절차 중 "공모 단계"에서 이루어지는 것은?', '외부감사 법인 선임 및 주간사 증권사 선정', '금융위원회 증권신고서 제출 및 거래소 심사', '기관 투자자 수요예측으로 공모가 결정 및 일반 투자자 청약', '거래소에서 일반 투자자 간 자유 거래 시작', 3, '문서 A.2-1 상장절차 한눈에 보기에서 3단계 공모에서 기관 투자자 수요예측으로 공모가가 결정되고, 일반 투자자 청약(보통 2일, 증권사 앱)이 이루어진다고 설명합니다.'),
(11, 6, '12', 'IPO 상장', '문서에서 "따상"의 의미로 제시된 것은?', '시초가가 공모가보다 30% 높게 형성된 것', '공모가 대비 시초가 2배 + 당일 상한가(+30%) 달성으로 공모가 대비 약 2.6배', '상장 첫날 거래가 시작될 때의 첫 번째 가격이 공모가와 같은 것', '상장 직후 주가가 급락하여 공모가를 밑도는 현상', 2, '문서 A.2-1 공모가 vs 시초가 vs 상한가 표에서 따상은 시초가가 공모가의 2배 + 당일 상한가(+30%) 달성으로 공모가 대비 약 2.6배에 달하는 것이라고 설명합니다.'),
(11, 7, '12', '주식 거래', '문서에서 한국 주식시장의 정규 장 거래 시간으로 제시된 것은?', '08:00 ~ 15:30', '08:30 ~ 15:00', '09:00 ~ 15:30', '09:00 ~ 16:00', 3, '문서 A.3 거래 시간 표에서 한국 주식시장 정규 장 시간은 09:00 ~ 15:30이라고 설명합니다.'),
(11, 8, '12', '주문 종류', '문서에서 지정가 주문(Limit Order, 보통가)의 특징으로 제시된 것은?', '현재 시장 가격으로 즉시 체결되는 주문으로 체결 속도가 빠르다', '투자자가 직접 가격을 지정하여 지정 가격 조건 미충족 시 당일 장 종료까지 대기한다', '즉시 체결 가능한 수량만 체결되고 나머지는 자동 취소되는 주문이다', '전량 즉시 체결 또는 전량 취소되는 주문으로 분할 체결을 거부한다', 2, '문서 A.4 지정가 주문 섹션에서 지정가(보통가) 주문은 투자자가 직접 매수·매도 가격을 지정하고, 조건 미충족 시 당일 장 종료까지 대기하는 주문 방식이라고 설명합니다.'),
(11, 9, '12', '거래 비용', '문서에서 증권거래세가 부과되는 시점으로 제시된 것은?', '주식 매수 시에만 부과된다', '주식 매수·매도 각각 부과된다', '주식 매도 시에만 부과된다', '보유 기간 1년 경과 후 자동 부과된다', 3, '문서 A.5 거래 비용 표에서 증권거래세는 매도 시에만 부과된다고 설명합니다(코스피 0.18%, 코스닥 0.18%, 2024년 기준).'),
(11, 10, '12', '고객예탁금', '문서에서 고객예탁금의 보호 방식으로 제시된 것은?', '예금자보호법에 따라 5,000만원까지 보호된다', '증권사가 자체 자금과 통합 운용하며 운용 수익을 투자자에게 배분한다', '한국증권금융(KSFC)에 별도 예치하여 증권사 파산 시에도 투자자 예탁금이 보호된다', '한국은행이 최종 보증인으로 전액 보호된다', 3, '문서 A.6 고객예탁금 표에서 고객예탁금은 한국증권금융(KSFC)에 별도 예치되어 증권사 파산과 무관하게 보호된다고 설명합니다.'),
(11, 11, '12', '배당 상식', '문서에서 배당락일(配當落日)의 설명으로 제시된 것은?', '이사회가 배당 결정을 공식 발표하는 날', '실제 배당금이 주주 계좌에 입금되는 날', '배당기준일 전날로, 이 날 매수하면 배당을 받지 못하는 날', '주주명부에 주주로 확정되어 배당 수령 자격이 생기는 날', 3, '문서 B.2 배당 관련 핵심 날짜 표에서 배당락일은 기준일 전날로, 이 날 매수하면 T+2 결제로 배당기준일 이후에 주주가 확정되어 배당을 받지 못한다고 설명합니다.'),
(11, 12, '12', '배당 지표', '문서에서 배당수익률(配當收益率)의 계산식으로 제시된 것은?', '총 배당금 ÷ 발행주식수', 'DPS ÷ 현재 주가 × 100', '배당총액 ÷ 당기순이익 × 100', '전년 DPS 대비 증가율', 2, '문서 B.3 배당 관련 지표 표에서 배당수익률은 DPS(주당배당금) ÷ 현재 주가 × 100으로 계산하며, 주가 대비 배당 수익 비율을 나타낸다고 설명합니다.'),
(11, 13, '12', '배당 세금', '문서에서 국내 주식 배당에 적용되는 원천징수 세율로 제시된 것은?', '9.9% (소득세 9% + 지방소득세 0.9%)', '15.4% (소득세 14% + 지방소득세 1.4%)', '22% (소득세 20% + 지방소득세 2%)', '33% (소득세 30% + 지방소득세 3%)', 2, '문서 B.4 배당 세금 표에서 국내 주식 배당에는 15.4%(소득세 14% + 지방소득세 1.4%)가 원천징수되며, 금융소득 2,000만원 초과 시 종합과세된다고 설명합니다.'),
(11, 14, '12', '주주환원', '문서에서 주주환원율(총주주환원율) 계산식으로 제시된 것은?', '(자사주 매입액 - 배당총액) ÷ 당기순이익 × 100', '배당총액 ÷ 당기순이익 × 100', '(배당총액 + 자사주 매입액) ÷ 당기순이익 × 100', '자사주 소각액 ÷ 시가총액 × 100', 3, '문서 B.5 주주환원율 섹션에서 주주환원율(%) = (배당총액 + 자사주 매입액) ÷ 당기순이익 × 100으로 계산한다고 설명합니다.'),
(11, 15, '12', '원금손실', '문서에서 은행 예금과 달리 원금손실 가능성이 있는 상품으로 제시된 것은?', '정기예금 (5천만원까지 예금자보호)', '정기적금', 'ETF (최대 100% 손실 가능)', 'CMA (수시입출금 가능 예금성 상품)', 3, '문서 C.3 다양한 투자 상품과 손실 가능성 표에서 ETF는 원금 비보장이며 최대 100%(0원) 손실이 가능하고, 정기예금·CMA 등 은행성 예금은 예금자보호로 원금이 보장된다고 설명합니다.'),
(11, 16, '12', '금융상품 구분', '문서에서 수신성 상품의 핵심 특징으로 제시된 것은?', '위험 보장이 핵심 목적이며 보험료를 납입한다', '자산 증식이 핵심 목적이며 원금 손실이 가능하다', '원금 보존과 이자가 핵심 목적이며 예금자보호(5천만원)가 적용된다', '배당 수익이 핵심 목적이며 자본시장법의 적용을 받는다', 3, '문서 E.1 수신성·보장성·투자성 구분 표에서 수신성(저축·예금) 상품은 원금 보존 + 이자가 핵심 목적이며 예금자보호(5천만원)가 적용된다고 설명합니다.'),
(11, 17, '12', '금융상품 구분', '문서에서 자본시장법상 금융투자상품의 정의로 제시된 것은?', '"이자 수익이 보장되는" 상품으로 은행법·저축은행법의 적용을 받는 상품', '"원본(원금) 손실 가능성"이 있는 상품으로 투자자 보호를 위해 설명의무·적합성 원칙이 적용되는 상품', '"만기 시 원금이 보장되는" 파생결합증권 계열 상품', '"정부 또는 공기업이 원금을 보증하는" 국채 계열 상품', 2, '문서 E.3 자본시장법 금융투자상품 분류에서 금융투자상품은 "원본(원금) 손실 가능성"이 있는 상품이며, 투자자 보호를 위해 설명의무·적합성 원칙이 적용된다고 설명합니다.'),
(11, 18, '12', '금융상품 구분', '문서에서 ETF(상장지수펀드)의 특징으로 제시된 것은?', '만기 전 환매가 제한되어 장기 대체투자에 적합한 폐쇄형 구조', '운용전문가가 초과수익을 추구하는 액티브 운용 상품', '장중 실시간 거래가 가능한 상장형 펀드', '원금이 보장되며 예금자보호법의 적용을 받는 수신성 상품', 3, '문서 E.4 펀드상품 보완 정리 표에서 ETF는 상장 펀드로 장중 실시간 거래가 가능하며, 거래 편의성을 중시하는 투자자에게 적합하다고 설명합니다.'),
(11, 19, '12', '해외 투자', '문서에서 해외 투자 시 "환헤지 선택 전략"에 대한 설명으로 제시된 것은?', '환헤지 상품은 수익률이 항상 환노출 상품보다 높다', '단기는 환헤지, 장기는 환노출 병행으로 환율 변동을 완충할 수 있다', '환헤지는 비용이 없으므로 모든 해외 투자 상품에 적용하는 것이 유리하다', '환노출 ETF는 원화 가치가 하락할 때 달러 환산 수익률이 증가한다', 2, '문서 G.3 해외 증권투자전략 표에서 환헤지 선택 전략은 단기에는 환헤지, 장기에는 환노출을 병행하여 환율 변동을 완충할 수 있다고 설명합니다.'),
(11, 20, '12', '증권분석', '문서에서 절대가치평가(Absolute Valuation)의 핵심 아이디어로 제시된 것은?', '유사 기업과 비교하여 저평가 여부를 판단한다', '순자산 중심으로 청산가치를 산정한다', '미래 현금흐름을 현재가치로 할인하여 가치를 평가한다', 'PER, PBR 등의 배수를 활용하여 상대적 가치를 비교한다', 3, '문서 H.2 유가증권의 가치평가(Valuation) 표에서 절대가치평가는 미래 현금흐름을 현재가치로 할인하는 방식으로 DCF, DDM 등이 대표 지표라고 설명합니다.'),
(11, 21, '12', '증권분석', '문서에서 PBR(주가순자산비율)의 해석 포인트로 제시된 것은?', 'PBR이 낮을수록 수익 대비 고평가 가능성이 높아 주의가 필요하다', 'PBR 1배 미만이면 자산가치 대비 저평가 가능성이 있다', 'PBR이 높을수록 기업의 배당 수익률이 높다', 'PBR은 기업가치를 EBITDA로 나누어 자본구조 차이를 줄여 비교한다', 2, '문서 H.2 가치평가 지표 표에서 PBR은 주가 ÷ BPS로 계산하며, 1배 미만이면 자산가치 대비 저평가 가능성이 있다고 설명합니다.'),
(11, 22, '12', '기술적 분석', '문서에서 상승추세(Uptrend)의 실전 기준으로 제시된 것은?', '20일선 < 60일선이며 고점·저점이 함께 낮아지는 추세', '20일선 > 60일선이며 저점이 상향하는 추세', '60일선과 120일선이 수평으로 나란히 움직이는 횡보 구간', '거래량이 감소하면서 주가가 박스권 내에서 등락을 반복하는 구간', 2, '문서 I.2 추세 분석 표에서 상승추세는 고점·저점이 함께 높아지며 20일선 > 60일선, 저점 상향이 실전 기준이라고 설명합니다.'),
(11, 23, '12', '기술적 분석', '문서에서 이중바닥(W) 패턴의 의미로 제시된 것은?', '상승 추세 종료 후 하락 전환 가능성을 나타내며 넥라인 이탈 시 하락 경고', '하락 후 반등 시도로 넥라인 돌파 시 반전 신호', '변동성 축소 후 방향성 대기 상태로 돌파 방향으로 추세 재개', '수급 균형 구간으로 상단 저항·하단 지지 활용', 2, '문서 I.3 패턴 분석 표에서 이중바닥(W) 패턴은 하락 후 반등 시도로, 넥라인 돌파 시 반전 신호로 해석된다고 설명합니다.'),
(11, 24, '12', '캔들 차트', '문서에서 양봉(陽棒)과 음봉(陰棒)의 구분 기준으로 제시된 것은?', '양봉은 거래량이 전일보다 증가한 날이고, 음봉은 거래량이 감소한 날이다', '양봉은 종가가 시가보다 높은 날이고, 음봉은 종가가 시가보다 낮은 날이다', '양봉은 주가가 전일 대비 상승한 날이고, 음봉은 하락한 날이다', '양봉은 52주 신고가를 경신한 날이고, 음봉은 52주 신저가를 경신한 날이다', 2, '문서 I.4-1 캔들 한 봉(OHLC) 아주 쉽게 읽기에서 종가가 시가보다 높으면 양봉, 낮으면 음봉이라고 설명합니다.'),
(11, 25, '12', '기술적 지표', '문서에서 RSI(Relative Strength Index) 지표의 과매수 기준으로 제시된 것은?', 'RSI 30 이상이면 과매수 구간으로 해석한다', 'RSI 50 이상이면 과매수 구간으로 해석한다', 'RSI 70 이상이면 과매수 구간으로 해석한다', 'RSI 80 이상이면 과매도 구간으로 해석한다', 3, '문서 I.5 지표 분석 표에서 RSI는 70 이상이면 과매수, 30 이하이면 과매도로 해석하는 과매수·과매도 진단 지표라고 설명합니다.'),
(11, 26, '12', '기술적 지표', '문서에서 골든크로스(Golden Cross)의 정의로 제시된 것은?', '단기 MA가 장기 MA를 위에서 아래로 이탈하는 신호', '단기 MA가 장기 MA를 아래에서 위로 돌파하는 신호로 보통 상승 전환으로 해석', '주가가 볼린저밴드 상단을 돌파하는 과매수 신호', 'MACD 선이 시그널선 아래로 이탈하는 하락 전환 신호', 2, '문서 I.5-2 골든크로스 vs 데드크로스에서 골든크로스는 단기 MA가 장기 MA를 아래에서 위로 돌파하는 신호로 보통 상승 전환 신호로 해석된다고 설명합니다.'),
(11, 27, '12', '산업분석', '문서에서 산업 라이프사이클의 성숙기(Maturity)에 적합한 투자전략으로 제시된 것은?', '소수 선도기업 선별로 높은 변동성을 감수하는 전략', '매출 고성장 기업 중심의 공격적 투자 전략', '배당·현금흐름 우수 기업을 선호하는 안정 지향 전략', '턴어라운드·재편 수혜 여부를 점검하는 재건 전략', 3, '문서 J.4 라이프사이클 분석 표에서 성숙기는 성장 둔화·효율·점유율 경쟁 단계로 배당/현금흐름 우수 기업을 선호하는 투자전략이 적합하다고 설명합니다.'),
(11, 28, '12', '순환매', '문서에서 경기 확장기(회복→확장 국면)에 강세를 보이는 섹터로 제시된 것은?', '헬스케어, 유틸리티, 필수소비재', 'IT, 산업재, 소재', '금융, 경기민감 소비재', '채권, 방어주', 2, '문서 J.8 순환매 표에서 회복→확장 국면에는 설비투자·기업이익이 빠르게 성장하며 IT, 산업재, 소재가 강세를 보인다고 설명합니다.'),
(11, 29, '12', '자산배분', '문서에서 전략적 자산배분(Strategic Asset Allocation)의 특징으로 제시된 것은?', '경기·밸류·수급 변화에 맞춰 단기적으로 비중을 조정하는 방식', '목표 비중 대비 ±5~15% 범위 내 오버/언더웨이트를 활용하는 방식', '최소 보장 자산(바닥가치)을 지키면서 위험자산 비중을 조절하는 CPPI 전략', '장기 기대수익과 위험을 기준으로 기준 비중을 설정하고 연 1~2회 점검하는 방식', 4, '문서 K.3 전략적 자산배분 표에서 전략적 자산배분은 장기 기대수익과 위험을 기준으로 기준 비중(Target Weight)을 설정하고 연 1~2회 점검하며, 감정 매매 억제와 장기 일관성 확보가 장점이라고 설명합니다.'),
(11, 30, '12', '성과평가', '문서에서 샤프지수(Sharpe Ratio)의 계산 개념으로 제시된 것은?', '초과수익률 ÷ 추적오차(Tracking Error)', '연환산수익률 ÷ 최대낙폭(MDD)', '(포트수익률 - 무위험수익률) ÷ 변동성', '(초과수익률) ÷ 하방변동성', 3, '문서 L.4 위험조정 성과지표 표에서 샤프지수(Sharpe Ratio)는 (포트수익률-무위험수익률) ÷ 변동성으로 계산하며, 높을수록 우수하고 1 이상이면 양호한 수준이라고 설명합니다.');
